-- Ken's Hardened V2 Fix

local b64_0x1llll1 = {}
local char_0x1IIl1I='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllII11=1,#char_0x1IIl1I do b64_0x1llll1[char_0x1IIl1I:sub(i_0xllII11,i_0xllII11)] = i_0xllII11 - 1 end

function b64_0x1llll1.dec_0xllIlIl(d_0xI1lllI)
    d_0xI1lllI = string.gsub(d_0xI1lllI, '[^'..char_0x1IIl1I..'=]', '')
    local r_0xIlllII = {}
    for i_0xllII11=1, #d_0xI1lllI, 4 do
        local c_0xlll1lI = b64_0x1llll1[d_0xI1lllI:sub(i_0xllII11,i_0xllII11)] or 0
        local c_0xllllIl = b64_0x1llll1[d_0xI1lllI:sub(i_0xllII11+1,i_0xllII11+1)] or 0
        local c_0xllIlI1, c_0xII1ll1 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xI1lllI:sub(i_0xllII11+2,i_0xllII11+2)
        if ch3 == "=" then has3 = false else c_0xllIlI1 = b64_0x1llll1[ch3] or 0 end
        local ch4 = d_0xI1lllI:sub(i_0xllII11+3,i_0xllII11+3)
        if ch4 == "=" then has4 = false else c_0xII1ll1 = b64_0x1llll1[ch4] or 0 end
        local b_0xIIl1lI = c_0xlll1lI * (2^18) + c_0xllllIl * (2^12) + c_0xllIlI1 * (2^6) + c_0xII1ll1
        local b_0xIll1ll = math.floor(b_0xIIl1lI / (2^16)) % (2^8)
        local b_0xlIlIII = math.floor(b_0xIIl1lI / (2^8)) % (2^8)
        local b_0xIl1lII = b_0xIIl1lI % (2^8)
        table.insert(r_0xIlllII, string.char(b_0xIll1ll))
        if has3 then table.insert(r_0xIlllII, string.char(b_0xlIlIII)) end
        if has4 then table.insert(r_0xIlllII, string.char(b_0xIl1lII)) end
    end
    return table.concat(r_0xIlllII)
end


local function bxor_0xllII11(a_0x11llll,b_0xllllI1)
    if bit32 then return bit32.bxor(a_0x11llll,b_0xllllI1) end
    local r_0xlI11lI = 0
    for i_0xlIII1I = 0, 7 do
        local x_0xIll1lI = a_0x11llll % 2
        local y_0xIl1IlI = b_0xllllI1 % 2
        if x_0xIll1lI ~= y_0xIl1IlI then r_0xlI11lI = r_0xlI11lI + (2^i_0xlIII1I) end
        a_0x11llll = math.floor(a_0x11llll / 2)
        b_0xllllI1 = math.floor(b_0xllllI1 / 2)
    end
    return r_0xlI11lI
end


local function bxor_str_0xlIIIlI(s_0xI1IllI, k_0xIl111l)
    local r_0xIIIl1I = {}
    for i_0xll1Ill=1, #s_0xI1IllI do
        local b_0xlIl1ll = string.byte(s_0xI1IllI, i_0xll1Ill)
        local kb_0x1lIl1I = string.byte(k_0xIl111l, (i_0xll1Ill-1) % #k_0xIl111l + 1)
        r_0xIIIl1I[i_0xll1Ill] = string.char(bxor_0xllII11(b_0xlIl1ll, kb_0x1lIl1I))
    end
    return table.concat(r_0xIIIl1I)
end


local function getkeys_0x1IlllI()
    local seed = b64_0x1llll1.dec_0xllIlIl("M3FrdGt3eFU=")
    local k1_enc = b64_0x1llll1.dec_0xllIlIl("eT9aRwYVCy0=")
    local k2_enc = b64_0x1llll1.dec_0xllIlIl("ajAPGSodGgI=")
    return bxor_str_0xlIIIlI(k1_enc, seed), bxor_str_0xlIIIlI(k2_enc, seed)
end


local function cff_0x11IIII(a_0x1lIII1)
    local st_0x1I11II = 0
    local res_0x1ll1lI = a_0x1lIII1
    while true do
        if st_0x1I11II == 0 then
            res_0x1ll1lI = res_0x1ll1lI + 1
            st_0x1I11II = 1
        elseif st_0x1I11II == 1 then
            res_0x1ll1lI = res_0x1ll1lI * 2
            st_0x1I11II = 2
        elseif st_0x1I11II == 2 then
            res_0x1ll1lI = res_0x1ll1lI - 3
            st_0x1I11II = 3
        else
            break
        end
    end
    return res_0x1ll1lI
end


local function chain_0xlll1II(x) return x*2 end
local function chain_0xI1lI11(x) return chain_0xlll1II(x)+1 end


local d_0xl1lIII = {
  {op=255, val="", is_enc=true},
}
local pc_0xI1IIlI = 1
local stk_0xIII11I = {}
stk_0xIII11I._jmp = nil


local disp_0xl1IIII = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x1IlllI()

local state_0xI1Ill1 = 0
while true do
    if state_0xI1Ill1 == 0 then  -- FETCH
        if pc_0xI1IIlI > #d_0xl1lIII then break end
        local inst = d_0xl1lIII[pc_0xI1IIlI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0x1llll1.dec_0xllIlIl(val)
            d = bxor_str_0xlIIIlI(d, k2)
            val = bxor_str_0xlIIIlI(d, k1)
        end
        stk_0xIII11I._jmp = nil
        pc_0xI1IIlI = pc_0xI1IIlI + 1
        cur_op_0x11Il1I = opcode
        cur_val_0xlIII1I = val
        state_0xI1Ill1 = 1

    elseif state_0xI1Ill1 == 1 then  -- EXECUTE
        local handler = disp_0xl1IIII[cur_op_0x11Il1I]
        if handler then
            handler(stk_0xIII11I, cur_val_0xlIII1I)
        end
        if stk_0xIII11I._jmp then
            pc_0xI1IIlI = pc_0xI1IIlI + stk_0xIII11I._jmp
        end
        state_0xI1Ill1 = 0
    else
        break
    end
end
